            <h2 class="font-display text-lg font-bold text-ink mb-1">Visualisasi Denah Tersedia Segera</h2>
            <p class="text-sm text-ink/50 text-center max-w-sm">Integrasi modul peta interaktif sedang dalam tahap pengembangan. Untuk sementara silakan gunakan navigasi daftar indeks di samping.</p>
        </div>
    </div>

    <style>
        .highlight-glow {
            fill: rgba(79, 70, 229, 0.15) !important; /* Warna isi Indigo transparan */
            stroke: #4f46e5 !important; /* Garis tepi Indigo khas aplikasi Anda */
            stroke-width: 2.5px !important; /* Garis sedikit lebih tebal dan tegas */
            filter: drop-shadow(0px 4px 8px rgba(79, 70, 229, 0.4)) !important; /* Bayangan biru bercahaya */
            transition: all 0.3s ease-in-out;
        }
        .custom-scrollbar::-webkit-scrollbar {
            width: 4px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
            background-color: #e5e7eb;
            border-radius: 10px;
        }
        .pagination-ringkas nav > div:last-child > div:first-child {
            display: none !important; /* Menyembunyikan teks "Showing X to Y..." */
        }
        .pagination-ringkas nav > div:last-child {
            justify-content: center !important; /* Memusatkan kotak angka 1,2,3,4 */
            width: 100%;
        }
        .pagination-ringkas nav {
            justify-content: center !important;
        }
    </style>

    <script>
        document.addEventListener('DOMContentLoaded', function() {
            // 1. Logika Klik Manual (Tetap Ada)
            const tombolKelas = document.querySelectorAll('.btn-kelas');
            tombolKelas.forEach(tombol => {
                tombol.addEventListener('click', function() {
                    const ruanganAktif = document.querySelector('.highlight-glow');
                    if (ruanganAktif) ruanganAktif.classList.remove('highlight-glow');

                    const targetId = this.getAttribute('data-target');
                    const ruanganDiPeta = document.getElementById(targetId);
                    if (ruanganDiPeta) {
                        ruanganDiPeta.classList.add('highlight-glow');
                    }
                });
            });

            // 2. LOGIKA OTOMATIS DARI BERANDA
            // Cek apakah ada parameter 'room' di URL
            const urlParams = new URLSearchParams(window.location.search);
            const autoHighlight = urlParams.get('room');

            if (autoHighlight) {
                const targetElement = document.getElementById(autoHighlight);
                if (targetElement) {
                    // Beri jeda sedikit agar transisi terasa halus saat halaman baru terbuka
                    setTimeout(() => {
                        targetElement.classList.add('highlight-glow');
                        // Scroll otomatis agar ruangan yang menyala berada di tengah layar
                        targetElement.scrollIntoView({ behavior: 'smooth', block: 'center' });
                    }, 500);
                }
            }
        });
    </script>
@endsection
